import{_ as a,o as d,c as r,ai as e}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第五课：板块与行业","description":"","frontmatter":{},"headers":[],"relativePath":"guide/05-industry.md","filePath":"guide/05-industry.md","lastUpdated":0}'),o={name:"guide/05-industry.md"};function h(l,t,i,n,b,s){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第五课-板块与行业" tabindex="-1">第五课：板块与行业 <a class="header-anchor" href="#第五课-板块与行业" aria-label="Permalink to “第五课：板块与行业”">​</a></h1><p>大盘指数告诉你整体冷热，但真正能赚钱的是<strong>结构化的机会</strong>——哪些行业在涨，哪些在跌。</p><h2 id="一、什么是板块" tabindex="-1">一、什么是板块？ <a class="header-anchor" href="#一、什么是板块" aria-label="Permalink to “一、什么是板块？”">​</a></h2><p>板块就是<strong>按某种逻辑把股票分组</strong>。</p><table tabindex="0"><thead><tr><th>分组逻辑</th><th>例子</th></tr></thead><tbody><tr><td>行业</td><td>白酒板块、银行板块、半导体板块</td></tr><tr><td>地域</td><td>上海板块、雄安新区板块</td></tr><tr><td>概念</td><td>人工智能板块、芯片概念、新能源汽车概念</td></tr></tbody></table><blockquote><p>💡 板块是动态的，&quot;人工智能&quot;以前不是板块，现在成了最热的概念之一。</p></blockquote><h2 id="二、行业分类" tabindex="-1">二、行业分类 <a class="header-anchor" href="#二、行业分类" aria-label="Permalink to “二、行业分类”">​</a></h2><p>A股按行业分为以下大类：</p><h3 id="十大一级行业" tabindex="-1">十大一级行业 <a class="header-anchor" href="#十大一级行业" aria-label="Permalink to “十大一级行业”">​</a></h3><table tabindex="0"><thead><tr><th>行业</th><th>典型股票</th><th>特点</th></tr></thead><tbody><tr><td>🍺 食品饮料（白酒）</td><td>茅台、五粮液</td><td>业绩稳定，防御性强</td></tr><tr><td>🏦 银行</td><td>工商银行、招商银行</td><td>低估值，高分红</td></tr><tr><td>💊 医药</td><td>恒瑞医药、药明康德</td><td>刚需，长期稳健</td></tr><tr><td>🔋 新能源</td><td>宁德时代、比亚迪</td><td>高成长，波动大</td></tr><tr><td>💻 半导体</td><td>中芯国际、寒武纪</td><td>政策支持，国产替代</td></tr><tr><td>🏗️ 房地产</td><td>万科、保利</td><td>周期性强，受政策影响大</td></tr><tr><td>☁️ 互联网</td><td>腾讯、阿里</td><td>港股为主，平台经济</td></tr><tr><td>🛢️ 能源</td><td>中国石油、中国石化</td><td>周期性强，受大宗商品影响</td></tr><tr><td>🏭 制造业</td><td>美的、格力、海尔</td><td>家电龙头，业绩稳定</td></tr><tr><td>🚗 汽车</td><td>比亚迪、上汽</td><td>转型新能源</td></tr></tbody></table><h2 id="三、热门板块的形成逻辑" tabindex="-1">三、热门板块的形成逻辑 <a class="header-anchor" href="#三、热门板块的形成逻辑" aria-label="Permalink to “三、热门板块的形成逻辑”">​</a></h2><h3 id="_1-政策驱动" tabindex="-1">1. 政策驱动 <a class="header-anchor" href="#_1-政策驱动" aria-label="Permalink to “1. 政策驱动”">​</a></h3><p>国家政策鼓励什么，什么板块就容易涨。</p><blockquote><p><strong>举例</strong>：国家大力发展新能源汽车 → 整车、电池、充电桩整个产业链都受益</p></blockquote><h3 id="_2-业绩驱动" tabindex="-1">2. 业绩驱动 <a class="header-anchor" href="#_2-业绩驱动" aria-label="Permalink to “2. 业绩驱动”">​</a></h3><p>某行业业绩普遍超预期，资金蜂拥买入。</p><blockquote><p><strong>举例</strong>：茅台业绩大增 → 白酒板块整体上涨</p></blockquote><h3 id="_3-题材驱动" tabindex="-1">3. 题材驱动 <a class="header-anchor" href="#_3-题材驱动" aria-label="Permalink to “3. 题材驱动”">​</a></h3><p>市场喜欢炒概念，跟风资金涌入。</p><blockquote><p><strong>举例</strong>：ChatGPT火 → 人工智能概念股连续涨停</p></blockquote><blockquote><p>⚠️ <strong>题材炒作风险极大</strong>，来得快去得也快，新手谨慎追题材。</p></blockquote><h2 id="四、如何发现热门板块" tabindex="-1">四、如何发现热门板块？ <a class="header-anchor" href="#四、如何发现热门板块" aria-label="Permalink to “四、如何发现热门板块？”">​</a></h2><h3 id="方法1-看涨幅榜" tabindex="-1">方法1：看涨幅榜 <a class="header-anchor" href="#方法1-看涨幅榜" aria-label="Permalink to “方法1：看涨幅榜”">​</a></h3><p>每天收盘后，在券商APP里看<strong>行业板块涨幅排名</strong>，涨幅最大的就是当天热门。</p><h3 id="方法2-看资金流向" tabindex="-1">方法2：看资金流向 <a class="header-anchor" href="#方法2-看资金流向" aria-label="Permalink to “方法2：看资金流向”">​</a></h3><p>资金往哪个板块流，哪个板块就可能有机会。</p><blockquote><p>东方财富APP：点&quot;数据中心&quot; → &quot;行业资金流向&quot;</p></blockquote><h3 id="方法3-看新闻" tabindex="-1">方法3：看新闻 <a class="header-anchor" href="#方法3-看新闻" aria-label="Permalink to “方法3：看新闻”">​</a></h3><p>政策利好、行业景气度提升，都可能引爆板块。</p><blockquote><p>建议关注：央视新闻、东方财富网、同花顺</p></blockquote><h2 id="五、板块轮动规律" tabindex="-1">五、板块轮动规律 <a class="header-anchor" href="#五、板块轮动规律" aria-label="Permalink to “五、板块轮动规律”">​</a></h2><p>不同市场环境下，资金会&quot;接力棒&quot;一样在不同板块之间流动：</p><h3 id="牛市各阶段" tabindex="-1">牛市各阶段 <a class="header-anchor" href="#牛市各阶段" aria-label="Permalink to “牛市各阶段”">​</a></h3><table tabindex="0"><thead><tr><th>牛市阶段</th><th>表现最好的板块</th></tr></thead><tbody><tr><td>初期</td><td>券商股（&quot;春江水暖鸭先知&quot;）</td></tr><tr><td>中期</td><td>消费、科技轮流表现</td></tr><tr><td>后期</td><td>银行、地产等蓝筹补涨</td></tr></tbody></table><h3 id="熊市-震荡市" tabindex="-1">熊市/震荡市 <a class="header-anchor" href="#熊市-震荡市" aria-label="Permalink to “熊市/震荡市”">​</a></h3><table tabindex="0"><thead><tr><th>市场环境</th><th>表现最好的板块</th></tr></thead><tbody><tr><td>熊市</td><td>医药、消费（防御性板块）</td></tr><tr><td>震荡市</td><td>题材股、短线机会</td></tr></tbody></table><h2 id="六、什么是-概念题材" tabindex="-1">六、什么是&quot;概念题材&quot;？ <a class="header-anchor" href="#六、什么是-概念题材" aria-label="Permalink to “六、什么是&quot;概念题材&quot;？”">​</a></h2><p>概念是比行业更细的分类，通常是<strong>一个热点主题</strong>带动的股票集合。</p><h3 id="常见概念举例" tabindex="-1">常见概念举例 <a class="header-anchor" href="#常见概念举例" aria-label="Permalink to “常见概念举例”">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>相关股票</th></tr></thead><tbody><tr><td>人工智能</td><td>科大讯飞、寒武纪、商汤</td></tr><tr><td>芯片国产替代</td><td>中芯国际、华大九天</td></tr><tr><td>新能源汽车</td><td>比亚迪、宁德时代、整车厂</td></tr><tr><td>创新药</td><td>恒瑞、百济神州</td></tr><tr><td>央企改革</td><td>中字头央企</td></tr></tbody></table><blockquote><p>⚠️ 概念炒作是&quot;击鼓传花&quot;，最后一个接盘的人会亏得很惨。</p></blockquote><h2 id="七、实操-怎么看板块" tabindex="-1">七、实操：怎么看板块 <a class="header-anchor" href="#七、实操-怎么看板块" aria-label="Permalink to “七、实操：怎么看板块”">​</a></h2><p>打开券商APP（以华泰涨乐财富通为例）：</p><ol><li>首页 → 点&quot;行情&quot;</li><li>选择&quot;板块&quot; → &quot;行业板块&quot;</li><li>按涨幅排序，看今日热门</li><li>点进某个板块，看成分股</li></ol><blockquote><p>💡 建议每天收盘后花5分钟看一下今日涨幅/跌幅前三的板块，培养市场感觉。</p></blockquote><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>今天&quot;人工智能&quot;板块涨幅第一，你会考虑买吗？买的时候要注意什么风险？</p></blockquote><hr><p><strong>下一课预告</strong>：了解了板块，下一课学习<strong>盘面基础知识</strong>——分时图、K线图、成交量。</p>',49)])])}const u=a(o,[["render",h]]);export{p as __pageData,u as default};
